// NuGet: AspNetCore.HealthChecks.NpgSql, AspNetCore.HealthChecks.Redis
builder.Services
    .AddHealthChecks()
    .AddNpgSql(
        conn,
        name: "postgresql",
        tags: ["ready"],
        timeout: TimeSpan.FromSeconds(3))
    .AddRedis(
        redisConn,
        name: "redis",
        tags: ["ready"],
        timeout: TimeSpan.FromSeconds(2))
    .AddCheck<DiskSpaceHealthCheck>("disk-space", tags: ["ready"])
    .AddCheck<ExternalApiHealthCheck>("payment-api", tags: ["ready"]);

// Endpoints phân biệt
app.MapHealthChecks("/health/live", new HealthCheckOptions
{
    Predicate = _ => false, // không chạy check nào — chỉ verify process alive
    ResponseWriter = WriteHealthResponse
});

app.MapHealthChecks("/health/ready", new HealthCheckOptions
{
    Predicate = check => check.Tags.Contains("ready"),
    ResponseWriter = WriteHealthResponse
}).RequireAuthorization("internal");

// Custom health check
public class DiskSpaceHealthCheck : IHealthCheck
{
    public Task<HealthCheckResult> CheckHealthAsync(HealthCheckContext ctx, CancellationToken ct)
    {
        var drive = DriveInfo.GetDrives().First(d => d.IsReady && d.Name == "/");
        var freePercent = 100.0 * drive.AvailableFreeSpace / drive.TotalSize;
        return Task.FromResult(freePercent < 10
            ? HealthCheckResult.Degraded($"Disk space thấp: {freePercent:F1}%")
            : HealthCheckResult.Healthy($"Disk OK: {freePercent:F1}% free"));
    }
}
